class Dog:
    def __init__(self, name):
        self.name = name

d = Dog('Rex')
print(type(d).__name__)

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y
    def __str__(self):
        return f'({self.x}, {self.y})'

v = Vector(3, 4)
print(v)

class A:
    def hello(self):
        return 'A'

class B(A):
    def hello(self):
        return 'B'

class C(B):
    pass

print(C().hello())

def decorator(func):
    def wrapper():
        print('before')
        func()
        print('after')
    return wrapper

@decorator
def greet():
    print('hello')

greet()

class Circle:
    def __init__(self, radius):
        self._radius = radius

    @property
    def radius(self):
        return self._radius

    @radius.setter
    def radius(self, value):
        if value < 0:
            raise ValueError('Radius cannot be negative')
        self._radius = value

c = Circle(5)
c.radius = 10
print(c.radius)
